import math

class BGESearchEngine:
    QUERY_PREFIX = "Represent this sentence for searching relevant passages: "

    def __init__(self, documents):
        self.documents = documents
        self.doc_vectors = [self.encode_document(doc) for doc in documents]

    def encode_document(self, text):
        words = text.lower().split()
        vec = {}
        for w in words:
            vec[w] = vec.get(w, 0) + 1
        return vec

    def encode_query(self, text):
        original_words = set(text.lower().split())
        full_text = self.QUERY_PREFIX + text
        vec = self.encode_document(full_text)
        for w in original_words:
            if w in vec:
                vec[w] = vec[w] * 2
        return vec

    def cosine_similarity(self, vec_a, vec_b):
        shared = set(vec_a) & set(vec_b)
        dot = sum(vec_a[w] * vec_b[w] for w in shared)
        mag_a = math.sqrt(sum(v**2 for v in vec_a.values()))
        mag_b = math.sqrt(sum(v**2 for v in vec_b.values()))
        if mag_a == 0 or mag_b == 0:
            return 0.0
        return dot / (mag_a * mag_b)

    def search(self, query, top_k=3):
        q_vec = self.encode_query(query)
        scored = [
            {"document": doc, "score": self.cosine_similarity(q_vec, dv)}
            for doc, dv in zip(self.documents, self.doc_vectors)
        ]
        scored.sort(key=lambda x: x["score"], reverse=True)
        return scored[:top_k]

    def search_no_prefix(self, query, top_k=3):
        q_vec = self.encode_document(query)  # No prefix boost
        scored = [
            {"document": doc, "score": self.cosine_similarity(q_vec, dv)}
            for doc, dv in zip(self.documents, self.doc_vectors)
        ]
        scored.sort(key=lambda x: x["score"], reverse=True)
        return scored[:top_k]

